using System.Collections.ObjectModel;using System.ComponentModel;using System.Runtime.CompilerServices;using System.Windows;using Exam.Core;using Exam.Data;namespace Exam.App;public partial class MainWindow:Window,INotifyPropertyChanged{readonly AgentRepository repo=new();List<Agent> all=new();int page=1;public ObservableCollection<Agent> PageItems{get;}=new();public List<string> Types{get;set;}=new();public string[] Sorts{get;}={"Title","Discount","Priority"};string search="";public string Search{get=>search;set{search=value;page=1;Refresh();}}string selectedType="All types";public string SelectedType{get=>selectedType;set{selectedType=value;page=1;Refresh();}}string selectedSort="Title";public string SelectedSort{get=>selectedSort;set{selectedSort=value;Refresh();}}public Agent? Selected{get;set;}public int MassValue{get;set;}public string Counter{get;set;}="";public RelayCommand AddCommand{get;}public RelayCommand EditCommand{get;}public RelayCommand DeleteCommand{get;}public RelayCommand MassCommand{get;}public RelayCommand NextCommand{get;}public RelayCommand PrevCommand{get;}public MainWindow(){InitializeComponent();DataContext=this;all=repo.Load();Types=all.Select(x=>x.Type).Distinct().Prepend("All types").ToList();AddCommand=new(_=>{all.Add(new Agent{Id=all.Count+1,Title="New agent",Type=Types.Skip(1).FirstOrDefault()??"Type",Priority=1});Save();});EditCommand=new(_=>{if(Selected!=null){Selected.Title+=" *";Save();}});DeleteCommand=new(_=>{if(Selected==null)return;if(!repo.CanDelete(Selected)){MessageBox.Show("Deletion is blocked: product sales exist.");return;}all.Remove(Selected);Save();});MassCommand=new(_=>{if(Selected!=null)Selected.Priority=MassValue;Save();});NextCommand=new(_=>{page++;Refresh();});PrevCommand=new(_=>{if(page>1)page--;Refresh();});Refresh();}void Save(){repo.Save(all);Refresh();}void Refresh(){IEnumerable<Agent> q=all;if(!string.IsNullOrWhiteSpace(Search))q=q.Where(x=>(x.Title+x.Email+x.Phone).Contains(Search,StringComparison.OrdinalIgnoreCase));if(SelectedType!="All types")q=q.Where(x=>x.Type==SelectedType);q=SelectedSort switch{"Discount"=>q.OrderBy(x=>x.Discount),"Priority"=>q.OrderBy(x=>x.Priority),_=>q.OrderBy(x=>x.Title)};var list=q.ToList();PageItems.Clear();foreach(var i in ListTools.Page(list,page,10))PageItems.Add(i);Counter=$"shown {PageItems.Count} of {list.Count}";OnPropertyChanged(nameof(Counter));}public event PropertyChangedEventHandler? PropertyChanged;void OnPropertyChanged([CallerMemberName]string? n=null)=>PropertyChanged?.Invoke(this,new PropertyChangedEventArgs(n));}
